using System.Collections.Generic;
using UnityEngine;
using UnityEngine.Events;

/// <summary>
/// Ponto de "Refúgio Seguro" (Save Manual): zona onde o jogador pode gravar
/// manualmente, mesmo em áreas ainda não totalmente desenhadas.
///
/// Detecta o player a entrar/saí no alcance (trigger) e, ao premir Interagir
/// dentro do alcance, dispara <see cref="onSaveMenuRequested"/> — o
/// SaveMenuController (Task #5, Menu de Save) liga-se aqui no Inspector para
/// abrir o menu em modo "guardar" (1 slot de autosave + até 30 manuais). A
/// escolha do slot e a escrita do ficheiro são feitas pelo SaveMenuController/
/// SaveManager, não por este componente.
/// </summary>
[RequireComponent(typeof(Collider2D))]
public class SafeHaven : MonoBehaviour
{
    [System.Serializable]
    public class BoolEvent : UnityEvent<bool> { }

    [Header("Identidade")]
    [Tooltip("ID único deste refúgio (ex: 'refugio_bosque_bruma'). Guardado em PlayerProgress.lastCheckpointId ao ser activado — usado como checkpoint.")]
    public string safeHavenId;

    [Tooltip("Nome a mostrar no feedback (ex: 'Refúgio Seguro — Bosque de Bruma'). Pode ficar vazio.")]
    public string displayName;

    [Header("Feedback Visual/Sonoro (opcional)")]
    [Tooltip("Activado enquanto o player está no alcance (ex: brilho/runa do refúgio).")]
    public SpriteRenderer glowSprite;

    [Tooltip("Som ao entrar no alcance do refúgio.")]
    public AudioClip enterRangeSfx;

    [Tooltip("Som ao premir Interagir dentro do alcance (antes do menu abrir).")]
    public AudioClip activateSfx;

    [Header("Eventos")]
    [Tooltip("Disparado quando o player, dentro do alcance, premir Interagir. O SaveMenuController deve ligar-se aqui para abrir o menu de save em modo 'guardar'.")]
    public UnityEvent onSaveMenuRequested;

    [Tooltip("Disparado quando o player entra (true) ou sai (false) do alcance.")]
    public BoolEvent onPlayerRangeChanged;

    /// <summary>
    /// Lista estática de todos os SafeHaven activos na cena — evita
    /// FindObjectsOfType em PlayerDeathHandler.ResolveCheckpointPosition.
    /// </summary>
    public static readonly List<SafeHaven> All = new List<SafeHaven>();

    private PlayerInputRouter _input;
    private bool _playerInRange;

    public bool PlayerInRange => _playerInRange;

    private void OnEnable() => All.Add(this);

    private void OnTriggerEnter2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        _playerInRange = true;

        _input = other.GetComponent<PlayerInputRouter>();
        if (_input != null) _input.InteractPressed += OnInteractPressed;

        if (glowSprite != null) glowSprite.enabled = true;
        if (enterRangeSfx != null) AudioManager.Instance?.PlaySE(enterRangeSfx);

        onPlayerRangeChanged?.Invoke(true);
    }

    private void OnTriggerExit2D(Collider2D other)
    {
        if (!other.CompareTag("Player")) return;

        _playerInRange = false;

        if (_input != null) _input.InteractPressed -= OnInteractPressed;
        _input = null;

        if (glowSprite != null) glowSprite.enabled = false;

        onPlayerRangeChanged?.Invoke(false);
    }

    private void OnDisable()
    {
        All.Remove(this);

        if (_input != null) _input.InteractPressed -= OnInteractPressed;
        _input = null;
    }

    private void OnInteractPressed()
    {
        if (!_playerInRange) return;

        // Mitigação do conflito de InteractPressed (pedido "InteractionManager"):
        // se outro sistema já reagiu a este toque (ex.: diálogo activo), não
        // abrimos também o menu de Safe Haven.
        if (_input != null && _input.InteractConsumed) return;

        if (activateSfx != null) AudioManager.Instance?.PlaySE(activateSfx);

        PlayerProgress.Instance?.SetLastCheckpoint(safeHavenId);

        onSaveMenuRequested?.Invoke();

        if (_input != null) _input.InteractConsumed = true;
    }
}
